class Solution:
    def maxPathScore(self, grid, k):
        m, n = len(grid), len(grid[0])
        best = [-1]
        def dfs(i, j, cost, score):
            if cost > k:
                return
            if i == m - 1 and j == n - 1:
                if score > best[0]:
                    best[0] = score
                return
            if i + 1 < m:
                v = grid[i + 1][j]
                c = 1 if v >= 1 else 0
                dfs(i + 1, j, cost + c, score + v)
            if j + 1 < n:
                v = grid[i][j + 1]
                c = 1 if v >= 1 else 0
                dfs(i, j + 1, cost + c, score + v)
        dfs(0, 0, 0, grid[0][0])
        return best[0]

