class Solution:
    def maxPathScore(self, grid, k):
        m, n = len(grid), len(grid[0])
        capC = min(k, m + n - 2)
        NEG = float('-inf')
        if capC < 0:
            return -1
        dp = [[[NEG] * (capC + 1) for _ in range(n)] for _ in range(m)]
        dp[0][0][0] = grid[0][0]
        for i in range(m):
            for j in range(n):
                if i == 0 and j == 0:
                    continue
                val = grid[i][j]
                cc = 1 if val >= 1 else 0
                row = dp[i][j]
                for c in range(capC + 1):
                    src = NEG
                    if i > 0 and dp[i - 1][j][c] != NEG:
                        src = dp[i - 1][j][c]
                    if j > 0 and dp[i][j - 1][c] != NEG and dp[i][j - 1][c] > src:
                        src = dp[i][j - 1][c]
                    if src == NEG:
                        continue
                    nc = c + cc
                    if nc > capC:
                        continue
                    if src + val > row[nc]:
                        row[nc] = src + val
        result = max(dp[m - 1][n - 1])
        return result if result != NEG else -1

