var maxPathScore = function(grid, k) {
    const m = grid.length, n = grid[0].length;
    const capC = Math.min(k, m + n - 2);
    const NEG = -Infinity;
    if (capC < 0) return -1;
    const dp = [];
    for (let i = 0; i < m; i++) {
        dp.push([]);
        for (let j = 0; j < n; j++) dp[i].push(new Array(capC + 1).fill(NEG));
    }
    dp[0][0][0] = grid[0][0];
    for (let i = 0; i < m; i++) {
        for (let j = 0; j < n; j++) {
            if (i === 0 && j === 0) continue;
            const val = grid[i][j];
            const cc = val >= 1 ? 1 : 0;
            const row = dp[i][j];
            for (let c = 0; c <= capC; c++) {
                let src = NEG;
                if (i > 0 && dp[i - 1][j][c] !== NEG) src = dp[i - 1][j][c];
                if (j > 0 && dp[i][j - 1][c] !== NEG && dp[i][j - 1][c] > src) src = dp[i][j - 1][c];
                if (src === NEG) continue;
                const nc = c + cc;
                if (nc > capC) continue;
                if (src + val > row[nc]) row[nc] = src + val;
            }
        }
    }
    const result = Math.max(...dp[m - 1][n - 1]);
    return result !== NEG ? result : -1;
};
